BEGIN
update TABLE_ORGANIZATION_ASSETS set update_date = #{item.updateDate,jdbcType=VARCHAR}, update_period = #{item.updatePeriod,jdbcType=VARCHAR}, DATARESOURCE_CODE = #{item.belongSystemCode,jdbcType=VARCHAR}, LASTDATAMODIFIEDTIME = #{item.lastDataModifiedTime,jdbcType=VARCHAR} where upper(TABLE_NAME_EN) = upper(#{item.tableName,jdbcType=VARCHAR}) and upper(TABLE_TYPE) = upper(#{item.organization,jdbcType=VARCHAR}) and upper(TABLE_PROJECT) = upper(#{item.projectName,jdbcType=VARCHAR}) and STATISTICS_TIME >= DATE_TRUNC('day', CURRENT_DATE) ;
END;
